import { useState, useRef, useCallback, useEffect } from "react";
import usePortfolioContext from "../../hooks/usePortfolioContext";

/* ── Operator Chat — sends execution commands to the AURA Operator ─ */

const PIN_CODE = "1121";

const MODELS = [
  { id: "gpt-4.1-mini", label: "GPT-4.1 Mini" },
  { id: "gpt-4.1", label: "GPT-4.1" },
  { id: "gpt-4.1-nano", label: "GPT-4.1 Nano" },
];

/* ── Pin Gate ──────────────────────────────────────────────────────── */
function PinGate({ onUnlock }) {
  const [pin, setPin] = useState("");
  const [error, setError] = useState(false);
  const [shake, setShake] = useState(false);
  const inputRef = useRef(null);

  useEffect(() => { inputRef.current?.focus(); }, []);

  const submit = () => {
    if (pin === PIN_CODE) {
      onUnlock();
    } else {
      setError(true);
      setShake(true);
      setTimeout(() => setShake(false), 500);
      setPin("");
      inputRef.current?.focus();
    }
  };

  return (
    <div style={{
      display: "flex", flexDirection: "column", alignItems: "center",
      justifyContent: "center", height: "100%", minHeight: "50vh",
      padding: "20px 16px",
      fontFamily: "'JetBrains Mono', monospace",
    }}>
      <div style={{
        padding: "clamp(24px, 5vw, 40px) clamp(20px, 4vw, 48px)",
        borderRadius: 14, background: "#161B22",
        border: "1px solid #30363D", textAlign: "center",
        boxShadow: "0 20px 60px rgba(0,0,0,0.4)",
        animation: shake ? "shake 0.4s ease-in-out" : undefined,
        width: "100%", maxWidth: 340,
      }}>
        <div style={{
          width: 48, height: 48, borderRadius: 14,
          background: "rgba(16,185,129,0.1)", border: "1px solid rgba(16,185,129,0.2)",
          display: "flex", alignItems: "center", justifyContent: "center",
          margin: "0 auto 16px", fontSize: 22,
        }}>
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#10B981" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
            <path d="M7 11V7a5 5 0 0 1 10 0v4" />
          </svg>
        </div>

        <div style={{ fontSize: 16, fontWeight: 700, color: "#E6EDF3", marginBottom: 8 }}>
          ChatGPT Access
        </div>
        <div style={{ fontSize: 11, color: "#8B949E", marginBottom: 20 }}>
          Enter PIN to continue
        </div>

        <div style={{ display: "flex", gap: 8, justifyContent: "center" }}>
          <input
            ref={inputRef}
            type="password"
            inputMode="numeric"
            maxLength={8}
            value={pin}
            onChange={(e) => { setPin(e.target.value); setError(false); }}
            onKeyDown={(e) => { if (e.key === "Enter") submit(); }}
            placeholder="----"
            style={{
              width: "100%", maxWidth: 140, padding: "12px 14px", borderRadius: 10,
              fontSize: 18, fontFamily: "'JetBrains Mono', monospace",
              background: "rgba(0,0,0,0.4)",
              border: `1px solid ${error ? "#EF4444" : "#30363D"}`,
              color: "#E6EDF3", outline: "none", textAlign: "center",
              letterSpacing: "4px", transition: "border-color 0.25s",
              minHeight: 44,
            }}
          />
          <button
            onClick={submit}
            style={{
              padding: "12px 20px", borderRadius: 10, fontSize: 13,
              fontWeight: 600, fontFamily: "'Plus Jakarta Sans', sans-serif",
              background: "rgba(16,185,129,0.15)", border: "1px solid rgba(16,185,129,0.3)",
              color: "#10B981", cursor: "pointer", transition: "all 0.25s",
              minHeight: 44,
            }}
            onMouseEnter={(e) => { e.target.style.background = "rgba(16,185,129,0.25)"; }}
            onMouseLeave={(e) => { e.target.style.background = "rgba(16,185,129,0.15)"; }}
          >
            Unlock
          </button>
        </div>

        {error && (
          <div style={{ marginTop: 12, fontSize: 11, color: "#EF4444" }}>
            Invalid PIN. Try again.
          </div>
        )}
      </div>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          20% { transform: translateX(-8px); }
          40% { transform: translateX(8px); }
          60% { transform: translateX(-6px); }
          80% { transform: translateX(6px); }
        }
      `}</style>
    </div>
  );
}

/* ── Step label helper ────────────────────────────────────────────── */
function stepLabel(step) {
  if (!step) return "executing...";
  if (step.type === "context_enrichment") return "Gathering system context...";
  if (step.type === "tool_call") return `Running: ${step.tool || "tool"}(${step.args ? Object.keys(step.args).join(", ") : ""})`;
  if (step.type === "tool_result") return `Result from: ${step.tool || "tool"}`;
  return step.type || "processing...";
}

function stepPreview(step) {
  if (!step) return null;
  if (step.context_preview) return step.context_preview;
  if (step.result_preview) {
    const p = step.result_preview;
    return p.length > 500 ? p.slice(0, 500) + "..." : p;
  }
  if (step.type === "tool_call" && step.args) {
    try { return JSON.stringify(step.args, null, 2); } catch { return null; }
  }
  return null;
}

/* ── Collapsible step detail ─────────────────────────────────────── */
function StepDetail({ step, index }) {
  const [open, setOpen] = useState(false);
  const preview = stepPreview(step);
  const icon = step.type === "context_enrichment" ? "\u{1F50D}"
    : step.type === "tool_call" ? "\u{1F527}"
    : step.type === "tool_result" ? "\u{1F4CB}"
    : "\u{2699}\u{FE0F}";

  return (
    <div style={{ fontSize: 11, color: "var(--v2-muted)" }}>
      <div
        onClick={() => preview && setOpen(!open)}
        style={{ cursor: preview ? "pointer" : "default", display: "flex", alignItems: "center", gap: 8, padding: "2px 0" }}
      >
        <span>{icon}</span>
        <span>{stepLabel(step)}</span>
        {preview && <span style={{ fontSize: 10, opacity: 0.6 }}>{open ? "\u25B2" : "\u25BC"}</span>}
      </div>
      {open && preview && (
        <pre style={{
          margin: "4px 0 4px 20px", padding: "6px 8px", fontSize: 10,
          background: "rgba(0,0,0,0.3)", borderRadius: 6, border: "1px solid rgba(255,255,255,0.05)",
          whiteSpace: "pre-wrap", wordBreak: "break-word", maxHeight: 200, overflow: "auto",
          color: "var(--v2-muted)",
        }}>{preview}</pre>
      )}
    </div>
  );
}

/* ── Chat Interface — routed to Operator (port 8001) ─────────────── */
function GPTChatInterface() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [liveSteps, setLiveSteps] = useState([]);  // steps arriving during stream
  const [model, setModel] = useState("gpt-4.1-mini");
  const [apiOk, setApiOk] = useState(null);
  const endRef = useRef(null);
  const abortRef = useRef(null);
  const inputRef = useRef(null);
  const stepsRef = useRef([]);  // mutable ref to capture steps for "done" event
  const { contextEnabled, setContextEnabled, refreshContext, contextLoading } = usePortfolioContext();

  const scrollBottom = useCallback(() => {
    setTimeout(() => endRef.current?.scrollIntoView({ behavior: "smooth" }), 50);
  }, []);

  // Check operator health on mount
  useEffect(() => {
    fetch("/operator/chat/health")
      .then(r => r.json())
      .then(() => setApiOk(true))
      .catch(() => setApiOk(false));
  }, []);

  const send = useCallback(async () => {
    const text = input.trim();
    if (!text || loading) return;

    setInput("");
    setMessages(prev => [...prev, { role: "user", text, ts: Date.now() }]);
    setLoading(true);
    setLiveSteps([]);
    stepsRef.current = [];
    scrollBottom();

    const ctrl = new AbortController();
    abortRef.current = ctrl;

    // Build message with portfolio context if enabled
    let messageToSend = text;
    if (contextEnabled) {
      const ctx = await refreshContext();
      if (ctx) {
        messageToSend = ctx + "\n\n" + text;
      }
    }

    try {
      const resp = await fetch("/operator/chat/stream", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: messageToSend, approve: true, model }),
        signal: ctrl.signal,
      });

      if (!resp.ok) throw new Error(await resp.text() || `HTTP ${resp.status}`);

      const reader = resp.body.getReader();
      const decoder = new TextDecoder();
      let buffer = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n");
        buffer = lines.pop() || "";

        for (const line of lines) {
          if (!line.startsWith("data: ")) continue;
          const payload = line.slice(6).trim();
          if (!payload || payload === "[DONE]") continue;
          try {
            const evt = JSON.parse(payload);
            if (evt.type === "start") {
              setLiveSteps([{ type: "start", label: `Connected to ${evt.model || "operator"}` }]);
              scrollBottom();
            } else if (evt.type === "step") {
              const stepInfo = evt.step || {};
              stepsRef.current = [...stepsRef.current, stepInfo];
              setLiveSteps(prev => [...prev, stepInfo]);
              scrollBottom();
            } else if (evt.type === "done") {
              const finalText = evt.final || "(no response)";
              const meta = [];
              if (evt.steps) meta.push(`${evt.steps} step${evt.steps !== 1 ? "s" : ""}`);
              if (evt.tool_calls) meta.push(`${evt.tool_calls} tool call${evt.tool_calls !== 1 ? "s" : ""}`);
              if (evt.seconds) meta.push(`${evt.seconds.toFixed(1)}s`);
              setMessages(prev => [...prev, {
                role: "assistant",
                text: finalText,
                ts: Date.now(),
                meta: meta.length ? meta.join(" \u00B7 ") : null,
                steps: stepsRef.current.length ? [...stepsRef.current] : null,
              }]);
              setLiveSteps([]);
              stepsRef.current = [];
              scrollBottom();
            } else if (evt.type === "error") {
              throw new Error(evt.detail || "Operator error");
            }
          } catch (e) {
            if (!(e instanceof SyntaxError)) throw e;
          }
        }
      }
    } catch (e) {
      if (e.name !== "AbortError") {
        setMessages(prev => [...prev, { role: "error", text: e.message, ts: Date.now() }]);
      }
    } finally {
      setLoading(false);
      abortRef.current = null;
      setLiveSteps([]);
      stepsRef.current = [];
      scrollBottom();
    }
  }, [input, loading, model, scrollBottom]);

  const stop = () => { abortRef.current?.abort(); setLoading(false); };
  const clear = () => { setMessages([]); setLiveSteps([]); };

  return (
    <div style={{ display: "flex", flexDirection: "column", height: "100%", overflow: "hidden", fontFamily: "'JetBrains Mono', monospace" }}>
      {/* Header */}
      <div className="v2-pagehead" style={{ flexShrink: 0, padding: "clamp(8px, 2vw, 10px) 2px" }}>
        <div style={{ minWidth: 0 }}>
          <h1 className="v2-h1" style={{ display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap" }}>
            <span style={{ fontSize: 22 }}>&#x1F916;</span> AURA Operator
          </h1>
          <div className="v2-muted">Execution commands — runs tasks on EC2</div>
        </div>
        <div className="v2-row" style={{ gap: 8, flexWrap: "wrap" }}>
          <select
            value={model}
            onChange={e => setModel(e.target.value)}
            style={{
              background: "var(--v2-surface)", border: "1px solid var(--v2-border)",
              color: "var(--v2-text)", borderRadius: 6, padding: "4px 8px",
              fontSize: 11, fontFamily: "inherit", minHeight: 36,
            }}
          >
            {MODELS.map(m => <option key={m.id} value={m.id}>{m.label}</option>)}
          </select>
          {/* Portfolio context toggle */}
          <button
            onClick={() => setContextEnabled(prev => !prev)}
            title={contextEnabled ? "Portfolio context active — click to disable" : "Portfolio context disabled — click to enable"}
            style={{
              display: "flex", alignItems: "center", gap: 4,
              padding: "4px 10px", borderRadius: 6, fontSize: 10, fontWeight: 600,
              fontFamily: "inherit", cursor: "pointer", minHeight: 36,
              background: contextEnabled ? "rgba(63,185,80,0.12)" : "rgba(255,255,255,0.04)",
              border: `1px solid ${contextEnabled ? "rgba(63,185,80,0.3)" : "var(--v2-border)"}`,
              color: contextEnabled ? "var(--v2-green)" : "var(--v2-muted)",
              transition: "all 0.25s",
            }}
          >
            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M21 12V7H5a2 2 0 0 1 0-4h14v4" />
              <path d="M3 5v14a2 2 0 0 0 2 2h16v-5" />
              <path d="M18 12a2 2 0 0 0 0 4h4v-4Z" />
            </svg>
            Portfolio
            {contextEnabled && (
              <span style={{
                width: 6, height: 6, borderRadius: "50%",
                background: contextLoading ? "var(--v2-amber, #F59E0B)" : "var(--v2-green)",
                flexShrink: 0,
                animation: contextLoading ? "blink 1s infinite" : undefined,
              }} />
            )}
          </button>
          <button className="v2-btn" onClick={clear} style={{ fontSize: 10, minHeight: 36 }}>Clear</button>
          {apiOk === false && (
            <span className="v2-pill v2-red" style={{ fontSize: 10 }}>OFFLINE</span>
          )}
          {apiOk === true && (
            <span className="v2-pill v2-green" style={{ fontSize: 10 }}>OK</span>
          )}
        </div>
      </div>

      {/* Messages */}
      <div style={{
        flex: 1, overflow: "auto", overflowX: "hidden",
        padding: "clamp(8px, 2vw, 12px) clamp(8px, 2vw, 16px)",
        display: "flex", flexDirection: "column", gap: 12,
        minHeight: 0, WebkitOverflowScrolling: "touch",
      }}>
        {messages.length === 0 && !loading && (
          <div style={{
            flex: 1, display: "flex", alignItems: "center", justifyContent: "center",
            flexDirection: "column", gap: 8, opacity: 0.5,
          }}>
            <div style={{ fontSize: 36 }}>&#x1F916;</div>
            <div style={{ fontSize: 13 }}>Send commands to the AURA Operator — it can execute tasks, check services, modify files, query data</div>
          </div>
        )}

        {messages.map((m, i) => (
          <div key={i} style={{
            display: "flex",
            justifyContent: m.role === "user" ? "flex-end" : "flex-start",
          }}>
            <div style={{
              maxWidth: "85%", padding: "10px 14px", borderRadius: 14,
              fontSize: 13, lineHeight: 1.6, whiteSpace: "pre-wrap", wordBreak: "break-word",
              background: m.role === "user"
                ? "rgba(96,165,250,0.15)"
                : m.role === "error"
                ? "rgba(239,68,68,0.12)"
                : "rgba(255,255,255,0.05)",
              border: `1px solid ${
                m.role === "user" ? "rgba(96,165,250,0.25)"
                : m.role === "error" ? "rgba(239,68,68,0.25)"
                : "rgba(255,255,255,0.08)"
              }`,
              color: m.role === "error" ? "var(--v2-red)" : "var(--v2-text)",
            }}>
              {/* Execution steps (collapsible) */}
              {m.steps && m.steps.length > 0 && (
                <div style={{
                  marginBottom: 8, paddingBottom: 8,
                  borderBottom: "1px solid rgba(255,255,255,0.06)",
                }}>
                  <div style={{ fontSize: 10, fontWeight: 600, color: "var(--v2-green)", marginBottom: 4, textTransform: "uppercase", letterSpacing: 1 }}>
                    Execution Log
                  </div>
                  {m.steps.map((s, si) => <StepDetail key={si} step={s} index={si} />)}
                </div>
              )}
              {m.text}
              {m.meta && (
                <div style={{ marginTop: 8, fontSize: 10, color: "var(--v2-muted)", borderTop: "1px solid rgba(255,255,255,0.06)", paddingTop: 4 }}>
                  {m.meta}
                </div>
              )}
            </div>
          </div>
        ))}

        {/* Live execution steps */}
        {loading && liveSteps.length > 0 && (
          <div style={{ display: "flex", justifyContent: "flex-start" }}>
            <div style={{
              maxWidth: "85%", padding: "10px 14px", borderRadius: 14,
              background: "rgba(255,255,255,0.05)", border: "1px solid rgba(63,185,80,0.2)",
            }}>
              <div style={{ fontSize: 10, fontWeight: 600, color: "var(--v2-green)", marginBottom: 4, textTransform: "uppercase", letterSpacing: 1, display: "flex", alignItems: "center", gap: 8 }}>
                <span style={{ display: "inline-block", width: 6, height: 6, borderRadius: "50%", background: "var(--v2-green)", animation: "blink 1s infinite" }} />
                Operator Working...
              </div>
              {liveSteps.map((s, si) => <StepDetail key={si} step={s} index={si} />)}
            </div>
          </div>
        )}

        {loading && liveSteps.length === 0 && (
          <div style={{ display: "flex", justifyContent: "flex-start" }}>
            <div style={{
              padding: "10px 14px", borderRadius: 14,
              background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.08)",
              fontSize: 13, color: "var(--v2-muted)", display: "flex", alignItems: "center", gap: 8,
            }}>
              <span style={{ display: "inline-block", width: 8, height: 8, borderRadius: "50%", background: "var(--v2-green)", animation: "blink 1s infinite" }} />
              Connecting to operator...
            </div>
          </div>
        )}

        <div ref={endRef} />
      </div>

      {/* Input */}
      <div style={{
        flexShrink: 0, padding: "clamp(8px, 2vw, 12px) clamp(8px, 2vw, 16px)",
        borderTop: "1px solid var(--v2-border)",
        display: "flex", gap: 8, alignItems: "flex-end",
      }}>
        <textarea
          ref={inputRef}
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => {
            if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); send(); }
          }}
          placeholder="Command the Operator..."
          rows={1}
          autoComplete="off"
          style={{
            flex: 1, resize: "none", background: "var(--v2-surface)",
            border: "1px solid var(--v2-border)", borderRadius: 10,
            color: "var(--v2-text)", padding: "10px 14px",
            fontSize: 13, fontFamily: "inherit", lineHeight: 1.5,
            maxHeight: 120, overflow: "auto", minHeight: 44,
            minWidth: 0,
          }}
        />
        {loading ? (
          <button onClick={stop} className="v2-btn" style={{
            background: "rgba(239,68,68,0.15)", borderColor: "rgba(239,68,68,0.3)",
            color: "var(--v2-red)", padding: "10px clamp(10px, 2vw, 16px)",
            minHeight: 44, flexShrink: 0,
          }}>
            Stop
          </button>
        ) : (
          <button onClick={send} disabled={!input.trim()} className="v2-btn" style={{
            background: "rgba(96,165,250,0.15)", borderColor: "rgba(96,165,250,0.3)",
            color: "var(--v2-blue)", padding: "10px clamp(10px, 2vw, 16px)",
            opacity: input.trim() ? 1 : 0.4,
            minHeight: 44, flexShrink: 0,
          }}>
            Send
          </button>
        )}
      </div>

      <style>{`@keyframes blink { 0%,100% { opacity: 1; } 50% { opacity: 0; } }`}</style>
    </div>
  );
}

/* ── Exported wrapper with PIN gate ───────────────────────────────── */
export default function GPTChat() {
  const [unlocked, setUnlocked] = useState(() => {
    return sessionStorage.getItem("gpt_chat_unlocked") === "true";
  });

  const handleUnlock = () => {
    sessionStorage.setItem("gpt_chat_unlocked", "true");
    setUnlocked(true);
  };

  return (
    <div role="main" aria-label="GPT Chat" style={{ height: "100%", display: "flex", flexDirection: "column" }}>
      {unlocked ? (
        <GPTChatInterface />
      ) : (
        <PinGate onUnlock={handleUnlock} />
      )}
    </div>
  );
}
